
import { useEffect, useRef, useState } from "react";
import { useNavigate } from "react-router-dom";

const CAR_IMAGE = "data:image/jpeg;base64,";

export default function LandingPage() {
  const navigate = useNavigate();
  const [booted, setBooted] = useState(false);
  const [loadProgress, setLoadProgress] = useState(0);
  const [speed, setSpeed] = useState(248);
  const [rpm, setRpm] = useState(7800);
  const [gear, setGear] = useState(7);
  const [fuel, setFuel] = useState(68);
  const [range, setRange] = useState(412);
  const [temp, setTemp] = useState(94);
  const [battery, setBattery] = useState(98);
  const [gforce, setGforce] = useState({ x: 0.2, y: -0.8 });
  const [warning, setWarning] = useState(true);
  const [tick, setTick] = useState(0);
  const canvasRef = useRef(null);
  const rafRef = useRef(null);

  // Boot sequence
  useEffect(() => {
    let p = 0;
    const iv = setInterval(() => {
      p += Math.random() * 12 + 4;
      if (p >= 100) { p = 100; clearInterval(iv); setTimeout(() => setBooted(true), 600); }
      setLoadProgress(Math.min(100, p));
    }, 120);
    return () => clearInterval(iv);
  }, []);

  // Live stats
  useEffect(() => {
    const iv = setInterval(() => {
      setTick(t => t + 1);
      setSpeed(s => Math.max(200, Math.min(280, s + (Math.random() - 0.5) * 6)));
      setRpm(r => Math.max(6000, Math.min(8500, r + (Math.random() - 0.5) * 300)));
      setFuel(f => Math.max(60, Math.min(72, f + (Math.random() - 0.5) * 0.5)));
      setRange(r => Math.max(400, Math.min(420, r + (Math.random() - 0.5) * 1)));
      setTemp(t => Math.max(90, Math.min(98, t + (Math.random() - 0.5) * 1)));
      setGforce({ x: (Math.random() - 0.5) * 1.2, y: -0.6 + (Math.random() - 0.5) * 0.4 });
    }, 800);
    return () => clearInterval(iv);
  }, []);

  // RPM gauge canvas
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    const W = canvas.width, H = canvas.height;
    const cx = W / 2, cy = H / 2 + 10;
    const R = W * 0.42;

    ctx.clearRect(0, 0, W, H);

    // Outer ring glow
    ctx.save();
    ctx.shadowBlur = 20;
    ctx.shadowColor = "#00ff88";
    ctx.strokeStyle = "rgba(0,255,136,0.15)";
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.arc(cx, cy, R + 12, 0, Math.PI * 2);
    ctx.stroke();
    ctx.restore();

    // Track
    const startA = Math.PI * 0.75;
    const endA = Math.PI * 2.25;
    ctx.save();
    ctx.strokeStyle = "rgba(255,255,255,0.08)";
    ctx.lineWidth = 14;
    ctx.lineCap = "round";
    ctx.beginPath();
    ctx.arc(cx, cy, R, startA, endA);
    ctx.stroke();

    // RPM fill — green to red
    const rpmPct = (rpm - 1000) / 8000;
    const fillEnd = startA + rpmPct * (endA - startA);
    const grad = ctx.createLinearGradient(cx - R, cy, cx + R, cy);
    grad.addColorStop(0, "#00ff88");
    grad.addColorStop(0.5, "#ffd93d");
    grad.addColorStop(0.85, "#ff6b6b");
    grad.addColorStop(1, "#ff0044");
    ctx.strokeStyle = grad;
    ctx.lineWidth = 14;
    ctx.shadowBlur = 16;
    ctx.shadowColor = rpmPct > 0.85 ? "#ff0044" : "#00ff88";
    ctx.beginPath();
    ctx.arc(cx, cy, R, startA, fillEnd);
    ctx.stroke();
    ctx.restore();

    // Tick marks
    for (let i = 0; i <= 9; i++) {
      const a = startA + (i / 9) * (endA - startA);
      const isRed = i >= 8;
      const isMaj = i % 1 === 0;
      ctx.save();
      ctx.translate(cx + Math.cos(a) * (R - 20), cy + Math.sin(a) * (R - 20));
      ctx.rotate(a);
      ctx.strokeStyle = isRed ? "#ff4444" : "rgba(255,255,255,0.6)";
      ctx.lineWidth = isMaj ? 2 : 1;
      ctx.shadowBlur = isRed ? 8 : 0;
      ctx.shadowColor = "#ff4444";
      ctx.beginPath();
      ctx.moveTo(0, -8);
      ctx.lineTo(0, 8);
      ctx.stroke();
      ctx.restore();
      // Labels
      if (isMaj) {
        ctx.save();
        ctx.fillStyle = isRed ? "#ff6b6b" : "rgba(255,255,255,0.7)";
        ctx.font = "bold 11px monospace";
        ctx.textAlign = "center";
        ctx.textBaseline = "middle";
        ctx.translate(cx + Math.cos(a) * (R - 38), cy + Math.sin(a) * (R - 38));
        ctx.fillText(i, 0, 0);
        ctx.restore();
      }
    }

    // Center text
    ctx.fillStyle = "rgba(255,255,255,0.3)";
    ctx.font = "10px monospace";
    ctx.textAlign = "center";
    ctx.fillText("ENGINE RPM", cx, cy - 28);
    ctx.fillText("×1000", cx, cy - 16);

    ctx.fillStyle = "#00ff88";
    ctx.font = "bold 28px monospace";
    ctx.shadowBlur = 12;
    ctx.shadowColor = "#00ff88";
    ctx.fillText((rpm / 1000).toFixed(1), cx, cy + 10);

    ctx.shadowBlur = 0;
    ctx.fillStyle = "rgba(0,255,136,0.8)";
    ctx.font = "bold 20px monospace";
    ctx.fillText(`GEAR: ${gear}`, cx, cy + 36);
  }, [rpm, gear]);

  function handleEnter() {
    const el = document.getElementById("hud-landing");
    if (el) {
      el.style.transition = "all 1s ease";
      el.style.transform = "scale(1.1)";
      el.style.opacity = "0";
    }
    setTimeout(() => navigate("/dashboard"), 1000);
  }

  const fuelBarW = `${fuel}%`;
  const rpmPct = Math.round((rpm / 8500) * 100);

  return (
    <div id="hud-landing" style={{
      position: "fixed", inset: 0, overflow: "hidden",
      fontFamily: "'Courier New', monospace",
      background: "#000",
    }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@400;700;900&family=Share+Tech+Mono&display=swap');
        * { margin:0; padding:0; box-sizing:border-box; }

        @keyframes scan { 0%{top:-8%} 100%{top:108%} }
        @keyframes blink { 0%,100%{opacity:1} 50%{opacity:0.3} }
        @keyframes warnBlink { 0%,100%{background:rgba(255,80,0,0.25);border-color:rgba(255,80,0,0.8)} 50%{background:rgba(255,80,0,0.1);border-color:rgba(255,80,0,0.3)} }
        @keyframes hudFadeIn { from{opacity:0;transform:scale(0.97)} to{opacity:1;transform:scale(1)} }
        @keyframes bootOut { to{opacity:0;transform:scale(1.04)} }
        @keyframes pulse { 0%,100%{box-shadow:0 0 8px currentColor} 50%{box-shadow:0 0 20px currentColor} }
        @keyframes ticker { 0%{transform:translateX(0)} 100%{transform:translateX(-50%)} }
        @keyframes radarSpin { to{transform:rotate(360deg)} }
        @keyframes graphScroll { from{stroke-dashoffset:0} to{stroke-dashoffset:-200} }

        .hud-font { font-family:'Orbitron',monospace; }
        .mono { font-family:'Share Tech Mono',monospace; }

        .boot-screen {
          position:absolute; inset:0; z-index:300;
          background:#000;
          display:flex; flex-direction:column; align-items:center; justify-content:center;
          transition:opacity 0.7s ease;
        }
        .boot-screen.out { animation:bootOut 0.7s ease forwards; }

        .scanline {
          position:absolute; left:0; right:0; height:8%;
          background:linear-gradient(transparent, rgba(0,255,136,0.04), transparent);
          pointer-events:none; z-index:200;
          animation:scan 4s linear infinite;
        }
        .scanlines-overlay {
          position:absolute; inset:0; z-index:199; pointer-events:none;
          background:repeating-linear-gradient(
            0deg,
            transparent,
            transparent 3px,
            rgba(0,0,0,0.15) 3px,
            rgba(0,0,0,0.15) 4px
          );
        }

        .hud-panel {
          position:absolute;
          background:rgba(0,8,20,0.82);
          border:1px solid;
          backdrop-filter:blur(8px);
        }
        .panel-green { border-color:rgba(0,255,136,0.5); box-shadow:0 0 16px rgba(0,255,136,0.1),inset 0 0 12px rgba(0,255,136,0.04); }
        .panel-cyan { border-color:rgba(0,200,255,0.5); box-shadow:0 0 16px rgba(0,200,255,0.1),inset 0 0 12px rgba(0,200,255,0.04); }
        .panel-yellow { border-color:rgba(255,220,0,0.5); box-shadow:0 0 16px rgba(255,220,0,0.1); }
        .panel-warn { border-color:rgba(255,80,0,0.8); box-shadow:0 0 20px rgba(255,80,0,0.3); animation:warnBlink 1.2s ease infinite; }

        .panel-label {
          position:absolute; top:-10px; left:12px; padding:0 6px;
          background:rgba(0,8,20,0.95);
          font-size:10px; letter-spacing:2px; font-family:'Orbitron',monospace;
        }

        .corner-tl::before,.corner-tl::after,.corner-br::before,.corner-br::after {
          content:''; position:absolute; width:8px; height:8px;
        }
        .corner-tl::before { top:-1px;left:-1px; border-top:2px solid; border-left:2px solid; }
        .corner-tl::after { bottom:-1px;right:-1px; border-bottom:2px solid; border-right:2px solid; }

        .speed-display {
          font-family:'Orbitron',monospace; font-weight:900;
          font-size:72px; line-height:1;
          color:#fff;
          text-shadow:0 0 30px rgba(0,200,255,0.8), 0 0 60px rgba(0,200,255,0.4);
          letter-spacing:-2px;
        }
        .speed-unit { font-size:16px; font-weight:400; color:rgba(0,200,255,0.8); letter-spacing:3px; }
        .speed-label { font-size:11px; color:rgba(0,200,255,0.6); letter-spacing:4px; margin-bottom:4px; }

        .mini-graph { display:block; overflow:hidden; }

        .stat-row { display:flex; align-items:center; gap:8px; margin-bottom:10px; }
        .stat-key { font-size:10px; letter-spacing:2px; color:rgba(255,255,255,0.45); min-width:52px; }
        .stat-val { font-size:13px; letter-spacing:1px; color:#00ff88; }
        .stat-bar-track { flex:1; height:4px; background:rgba(255,255,255,0.08); border-radius:2px; overflow:hidden; }
        .stat-bar-fill { height:100%; border-radius:2px; transition:width 0.6s ease; }

        .nav-box {
          display:flex; align-items:center; gap:10px;
          background:rgba(0,255,136,0.08);
          border:1px solid rgba(0,255,136,0.4);
          border-radius:4px; padding:8px 14px;
          margin-bottom:10px;
        }
        .nav-arrow { font-size:22px; color:#00ff88; }
        .nav-street { font-family:'Orbitron',monospace; font-size:13px; font-weight:700; color:#fff; }
        .nav-dist { font-size:10px; color:rgba(255,255,255,0.5); letter-spacing:1px; margin-top:2px; }

        .map-display {
          width:100%; flex:1;
          background:rgba(0,20,40,0.9);
          border:1px solid rgba(0,200,255,0.2);
          border-radius:4px; position:relative; overflow:hidden;
        }

        .radar-container { position:relative; }
        .radar-sweep {
          position:absolute; inset:0;
          background:conic-gradient(from 0deg, transparent 0deg, rgba(0,255,136,0.4) 20deg, transparent 20deg);
          border-radius:50%;
          animation:radarSpin 3s linear infinite;
        }

        .bottom-bar {
          position:absolute; bottom:0; left:0; right:0;
          height:34px; background:rgba(0,0,0,0.85);
          border-top:1px solid rgba(0,200,255,0.2);
          display:flex; align-items:center; overflow:hidden; z-index:100;
        }
        .ticker-inner { display:flex; white-space:nowrap; animation:ticker 20s linear infinite; }
        .ticker-item { font-size:10px; letter-spacing:2px; padding:0 32px; display:flex; gap:10px; }

        .hud-enter-btn {
          position:absolute; bottom:50px; left:50%; transform:translateX(-50%);
          z-index:150;
          font-family:'Orbitron',monospace; font-size:13px; font-weight:700; letter-spacing:4px;
          padding:12px 40px; cursor:pointer; border:none;
          background:linear-gradient(90deg, rgba(0,255,136,0.15), rgba(0,200,255,0.15));
          border-top:1px solid rgba(0,255,136,0.6);
          border-bottom:1px solid rgba(0,200,255,0.6);
          border-left:1px solid rgba(0,200,255,0.3);
          border-right:1px solid rgba(0,255,136,0.3);
          color:#fff; backdrop-filter:blur(12px);
          transition:all 0.3s;
          text-shadow:0 0 10px rgba(0,255,136,0.8);
          box-shadow:0 0 20px rgba(0,200,255,0.2);
        }
        .hud-enter-btn:hover {
          background:linear-gradient(90deg, rgba(0,255,136,0.3), rgba(0,200,255,0.3));
          box-shadow:0 0 40px rgba(0,255,136,0.4);
          letter-spacing:6px;
        }

        .status-dot { width:6px; height:6px; border-radius:50%; display:inline-block; margin-right:6px; }
        .dot-green { background:#00ff88; box-shadow:0 0 6px #00ff88; }
        .dot-cyan { background:#00c8ff; box-shadow:0 0 6px #00c8ff; }

        .battery-bar {
          width:100%; height:16px; background:rgba(255,255,255,0.06);
          border:1px solid rgba(0,255,136,0.3); border-radius:2px; overflow:hidden; position:relative;
        }
        .battery-fill {
          height:100%; background:linear-gradient(90deg,#00ff88,#00c8ff);
          box-shadow:0 0 10px rgba(0,255,136,0.6);
          transition:width 0.8s ease;
        }
        .battery-label {
          position:absolute; inset:0; display:flex; align-items:center; justify-content:center;
          font-size:9px; letter-spacing:2px; color:rgba(0,0,0,0.8); font-weight:700;
          font-family:'Orbitron',monospace;
        }
      `}</style>

      {/* Real car photo as full background */}
      <div style={{
        position: "absolute", inset: 0, zIndex: 0,
        backgroundImage: `url(${CAR_IMAGE})`,
        backgroundSize: "cover", backgroundPosition: "center",
        filter: "brightness(0.65) contrast(1.1) saturate(0.8)",
      }} />

      {/* Dark vignette overlay */}
      <div style={{
        position: "absolute", inset: 0, zIndex: 1,
        background: "radial-gradient(ellipse at center, transparent 30%, rgba(0,0,0,0.7) 100%)",
        pointerEvents: "none",
      }} />

      {/* Scanlines */}
      <div className="scanlines-overlay" />
      <div className="scanline" />

      {/* ═══════════════ LEFT PANEL — SPEEDOMETER + RPM ═══════════════ */}
      <div className="hud-panel panel-cyan corner-tl" style={{
        left: 20, top: 20, width: 260, padding: "20px 18px",
        borderRadius: 6, zIndex: 10,
        animation: booted ? "hudFadeIn 0.6s ease 0.1s both" : "none",
      }}>
        <div className="panel-label" style={{ color: "rgba(0,200,255,0.8)" }}>VELOCITY</div>
        <div className="speed-label mono">SPEED:</div>
        <div className="speed-display">{Math.round(speed)}</div>
        <div className="speed-unit">KM/H</div>

        <div style={{ margin: "18px 0 10px", width: 220, height: 220, margin: "14px auto 0" }}>
          <canvas ref={canvasRef} width={220} height={220} />
        </div>
      </div>

      {/* ═══════════════ TOP CENTER — NAV ═══════════════ */}
      <div className="hud-panel panel-green" style={{
        top: 20, left: "50%", transform: "translateX(-50%)",
        width: 320, padding: "12px 16px", borderRadius: 6, zIndex: 10,
        animation: booted ? "hudFadeIn 0.6s ease 0.2s both" : "none",
      }}>
        <div className="panel-label" style={{ color: "rgba(0,255,136,0.8)" }}>NAV</div>
        <div className="nav-box">
          <div className="nav-arrow">↱</div>
          <div>
            <div className="nav-street">NEO-TOKYO EXPRESSWAY</div>
            <div className="nav-dist">1.2 KM to Exit</div>
          </div>
        </div>
        {/* Mini map */}
        <div className="map-display" style={{ height: 80, borderRadius: 3 }}>
          <svg width="100%" height="80" style={{ display: "block" }}>
            <defs>
              <linearGradient id="roadGrad" x1="0" y1="0" x2="1" y2="0">
                <stop offset="0%" stopColor="rgba(0,200,255,0.3)" />
                <stop offset="100%" stopColor="rgba(0,255,136,0.3)" />
              </linearGradient>
            </defs>
            {/* Road */}
            <path d="M0,60 Q80,40 160,50 Q240,60 290,30" stroke="url(#roadGrad)" strokeWidth="8" fill="none" opacity="0.6" />
            <path d="M0,60 Q80,40 160,50 Q240,60 290,30" stroke="rgba(255,255,255,0.15)" strokeWidth="2" fill="none" strokeDasharray="8,6" />
            {/* Current position */}
            <circle cx="120" cy="48" r="5" fill="#00ff88" />
            <circle cx="120" cy="48" r="10" fill="none" stroke="#00ff88" strokeWidth="1" opacity="0.5" />
            {/* Exit marker */}
            <circle cx="240" cy="58" r="4" fill="#ffd93d" />
            {/* Labels */}
            <text x="8" y="20" fill="rgba(0,200,255,0.6)" fontSize="8" fontFamily="monospace">ドア・アテワ</text>
            <text x="230" y="20" fill="rgba(0,200,255,0.6)" fontSize="8" fontFamily="monospace">NEO-TOKYO</text>
            <text x="232" y="30" fill="rgba(0,200,255,0.4)" fontSize="7" fontFamily="monospace">to Exit</text>
          </svg>
        </div>
      </div>

      {/* ═══════════════ TOP RIGHT — ROUTE GUIDANCE ═══════════════ */}
      <div className="hud-panel panel-green" style={{
        top: 20, right: 20, width: 200, padding: "12px 14px", borderRadius: 6, zIndex: 10,
        animation: booted ? "hudFadeIn 0.6s ease 0.3s both" : "none",
      }}>
        <div className="panel-label" style={{ color: "rgba(0,255,136,0.8)" }}>東京流路ダウン</div>
        <div style={{ fontSize: 11, color: "rgba(0,255,136,0.7)", letterSpacing: 1, marginBottom: 8 }}>Route guidance</div>
        <svg width="100%" height="90" style={{ display: "block", background: "rgba(0,20,40,0.6)", borderRadius: 3, border: "1px solid rgba(0,200,255,0.15)" }}>
          <text x="8" y="18" fill="rgba(0,200,255,0.5)" fontSize="8" fontFamily="monospace">ドア・アテワ ●——</text>
          <path d="M10,40 L130,40 L130,55 L160,55" stroke="rgba(0,255,136,0.6)" strokeWidth="3" fill="none" />
          <path d="M10,70 L100,70" stroke="rgba(0,200,255,0.3)" strokeWidth="1.5" fill="none" strokeDasharray="4,3" />
          <circle cx="14" cy="40" r="4" fill="#00ff88" />
          <circle cx="154" cy="55" r="4" fill="#ffd93d" />
          <text x="134" y="52" fill="#ffd93d" fontSize="7" fontFamily="monospace">EXIT</text>
          <text x="155" y="88" fill="rgba(0,200,255,0.5)" fontSize="8" fontFamily="monospace">NEO-TOKYO</text>
          <text x="155" y="78" fill="rgba(0,255,136,0.4)" fontSize="7" fontFamily="monospace">to Exit ▲</text>
        </svg>
      </div>

      {/* ═══════════════ CENTER RIGHT — TELEMETRY ═══════════════ */}
      <div className="hud-panel panel-cyan" style={{
        top: 20, right: 230, width: 190, padding: "14px 14px", borderRadius: 6, zIndex: 10,
        animation: booted ? "hudFadeIn 0.6s ease 0.25s both" : "none",
      }}>
        <div className="panel-label" style={{ color: "rgba(0,200,255,0.8)" }}>TELEMETRY</div>

        {/* FUEL */}
        <div style={{ marginBottom: 12 }}>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
            <span className="mono" style={{ fontSize: 10, letterSpacing: 2, color: "rgba(0,200,255,0.6)" }}>FUEL:</span>
            <span className="hud-font" style={{ fontSize: 12, color: "#fff", fontWeight: 700 }}>{Math.round(fuel)}%</span>
          </div>
          <div className="stat-bar-track">
            <div className="stat-bar-fill" style={{ width: `${fuel}%`, background: "linear-gradient(90deg,#ffd93d,#ff9f43)" }} />
          </div>
          <svg width="100%" height="28" style={{ marginTop: 2 }}>
            <polyline points={Array.from({length:20},(_,i)=>`${i*9},${14+Math.sin((tick+i)*0.7)*6}`).join(" ")} fill="none" stroke="rgba(255,217,61,0.5)" strokeWidth="1.5" />
          </svg>
        </div>

        {/* RANGE */}
        <div style={{ marginBottom: 12 }}>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
            <span className="mono" style={{ fontSize: 10, letterSpacing: 2, color: "rgba(0,200,255,0.6)" }}>RANGE:</span>
            <span className="hud-font" style={{ fontSize: 12, color: "#fff", fontWeight: 700 }}>{Math.round(range)} KM</span>
          </div>
          <div className="stat-bar-track">
            <div className="stat-bar-fill" style={{ width: "82%", background: "linear-gradient(90deg,#00ff88,#00c8ff)" }} />
          </div>
          <svg width="100%" height="28" style={{ marginTop: 2 }}>
            <polyline points={Array.from({length:20},(_,i)=>`${i*9},${14+Math.sin((tick+i)*0.5+1)*5}`).join(" ")} fill="none" stroke="rgba(0,255,136,0.5)" strokeWidth="1.5" />
          </svg>
        </div>

        {/* TEMP */}
        <div>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
            <span className="mono" style={{ fontSize: 10, letterSpacing: 2, color: "rgba(0,200,255,0.6)" }}>TEMP:</span>
            <span className="hud-font" style={{ fontSize: 12, color: temp > 95 ? "#ff6b6b" : "#fff", fontWeight: 700 }}>{Math.round(temp)}°C</span>
          </div>
          <div className="stat-bar-track">
            <div className="stat-bar-fill" style={{ width: `${((temp-80)/30)*100}%`, background: "linear-gradient(90deg,#4d96ff,#ff6b6b)" }} />
          </div>
          <svg width="100%" height="28" style={{ marginTop: 2 }}>
            <polyline points={Array.from({length:20},(_,i)=>`${i*9},${14+Math.sin((tick+i)*0.9+2)*5}`).join(" ")} fill="none" stroke="rgba(255,107,107,0.5)" strokeWidth="1.5" />
          </svg>
        </div>
      </div>

      {/* ═══════════════ LEFT BOTTOM — G-FORCE RADAR ═══════════════ */}
      <div className="hud-panel panel-green" style={{
        left: 20, bottom: 80, width: 180, padding: "14px", borderRadius: 6, zIndex: 10,
        animation: booted ? "hudFadeIn 0.6s ease 0.4s both" : "none",
      }}>
        <div className="panel-label" style={{ color: "rgba(0,255,136,0.8)" }}>G-FORCE</div>
        <div style={{ position: "relative", width: 140, height: 140, margin: "0 auto" }}>
          {/* Radar rings */}
          {[70,50,30,12].map(r => (
            <svg key={r} style={{ position: "absolute", inset: 0 }} width="140" height="140">
              <circle cx="70" cy="70" r={r} fill="none" stroke="rgba(0,255,136,0.15)" strokeWidth="1" />
            </svg>
          ))}
          {/* Cardinal lines */}
          <svg style={{ position: "absolute", inset: 0 }} width="140" height="140">
            <line x1="70" y1="0" x2="70" y2="140" stroke="rgba(0,255,136,0.1)" strokeWidth="0.5" />
            <line x1="0" y1="70" x2="140" y2="70" stroke="rgba(0,255,136,0.1)" strokeWidth="0.5" />
            <text x="70" y="10" textAnchor="middle" fill="rgba(0,255,136,0.5)" fontSize="9" fontFamily="monospace">N</text>
            <text x="70" y="136" textAnchor="middle" fill="rgba(0,255,136,0.5)" fontSize="9" fontFamily="monospace">S</text>
            <text x="6" y="73" fill="rgba(0,255,136,0.5)" fontSize="9" fontFamily="monospace">W</text>
            <text x="126" y="73" fill="rgba(0,255,136,0.5)" fontSize="9" fontFamily="monospace">E</text>
          </svg>
          {/* Radar sweep */}
          <div className="radar-sweep" style={{ position: "absolute", inset: 0, borderRadius: "50%" }} />
          {/* G-force dot */}
          <div style={{
            position: "absolute",
            left: 70 + gforce.x * 50 - 6,
            top: 70 + gforce.y * 50 - 6,
            width: 12, height: 12, borderRadius: "50%",
            background: "#00ff88",
            boxShadow: "0 0 12px #00ff88",
            transition: "all 0.6s ease",
          }} />
        </div>
      </div>

      {/* ═══════════════ BOTTOM CENTER — STATUS STRIP ═══════════════ */}
      <div className="hud-panel panel-cyan" style={{
        bottom: 80, left: "50%", transform: "translateX(-50%)",
        width: 340, padding: "12px 18px", borderRadius: 6, zIndex: 10,
        animation: booted ? "hudFadeIn 0.6s ease 0.5s both" : "none",
      }}>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "8px 24px" }}>
          {[
            { label: "ABS:", val: "OK", color: "#00ff88" },
            { label: "DRIVETRAIN:", val: "4WD", color: "#00c8ff" },
            { label: "TRACTION:", val: "SPORT", color: "#ffd93d" },
            { label: "LAUNCH:", val: "ACTIVE", color: "#00ff88" },
          ].map(({ label, val, color }) => (
            <div key={label} style={{ display: "flex", gap: 6, alignItems: "center" }}>
              <span className="mono" style={{ fontSize: 10, color: "rgba(255,255,255,0.4)", letterSpacing: 1 }}>{label}</span>
              <span className="hud-font" style={{ fontSize: 11, color, fontWeight: 700, textShadow: `0 0 8px ${color}` }}>{val}</span>
            </div>
          ))}
        </div>
      </div>

      {/* ═══════════════ WARNING PANEL ═══════════════ */}
      {warning && (
        <div className="hud-panel panel-warn" style={{
          right: 20, bottom: 150, width: 240, padding: "12px 14px", borderRadius: 6, zIndex: 10,
          animation: booted ? "hudFadeIn 0.6s ease 0.6s both" : "none",
        }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8 }}>
            <span style={{ color: "#ff8c00", fontSize: 13, animation: "blink 1s infinite" }}>⚠</span>
            <span className="hud-font" style={{ fontSize: 10, color: "#ff8c00", letterSpacing: 2, animation: "blink 1s infinite" }}>[WARNING]</span>
            <span style={{ color: "rgba(255,140,0,0.7)", fontSize: 16, marginLeft: "auto" }}>⚠</span>
          </div>
          <div className="hud-font" style={{ fontSize: 12, color: "#fff", fontWeight: 700, lineHeight: 1.5, letterSpacing: 1 }}>
            ANOMALY DETECTED:<br />HIGH-VOLTAGE SURGE
          </div>
          <div className="mono" style={{ fontSize: 10, color: "#ff8c00", marginTop: 6, letterSpacing: 2 }}>AVOID ROUTE 4B</div>
          <button onClick={() => setWarning(false)} style={{
            marginTop: 10, width: "100%", padding: "5px 0",
            background: "rgba(255,80,0,0.15)", border: "1px solid rgba(255,80,0,0.4)",
            color: "rgba(255,140,0,0.8)", fontSize: 9, letterSpacing: 2, cursor: "pointer",
            fontFamily: "'Orbitron',monospace",
          }}>ACKNOWLEDGE</button>
        </div>
      )}

      {/* ═══════════════ BOTTOM — BATTERY ═══════════════ */}
      <div className="hud-panel panel-green" style={{
        bottom: 80, right: 20, width: 200, padding: "12px 14px", borderRadius: 6, zIndex: 10,
        animation: booted ? "hudFadeIn 0.6s ease 0.55s both" : "none",
      }}>
        <div className="panel-label" style={{ color: "rgba(0,255,136,0.8)" }}>POWER</div>
        <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 6 }}>
          <span className="mono" style={{ fontSize: 10, color: "rgba(0,200,255,0.6)", letterSpacing: 2 }}>BATTERY:</span>
          <span className="hud-font" style={{ fontSize: 12, color: "#00ff88", fontWeight: 700 }}>{battery}%</span>
        </div>
        <div className="battery-bar">
          <div className="battery-fill" style={{ width: `${battery}%` }} />
          <div className="battery-label">{battery}% CHARGED</div>
        </div>
        <div style={{ marginTop: 10, display: "flex", gap: 6, flexWrap: "wrap" }}>
          {["REGEN ON","ECO MODE","BOOST RDY"].map(s => (
            <span key={s} className="mono" style={{
              fontSize: 8, letterSpacing: 1, padding: "2px 6px",
              border: "1px solid rgba(0,255,136,0.3)", color: "rgba(0,255,136,0.6)",
              borderRadius: 2,
            }}>{s}</span>
          ))}
        </div>
      </div>

      {/* ENTER BUTTON */}
      <button className="hud-enter-btn" onClick={handleEnter}>
        ▶ ENTER DASHBOARD
      </button>

      {/* TICKER */}
      <div className="bottom-bar">
        <div style={{ width: 80, flexShrink: 0, display: "flex", alignItems: "center", paddingLeft: 12, borderRight: "1px solid rgba(0,200,255,0.2)" }}>
          <span className="hud-font" style={{ fontSize: 8, color: "rgba(0,200,255,0.6)", letterSpacing: 1 }}>LIVE</span>
          <span className="status-dot dot-green" style={{ marginLeft: 6, animation: "blink 1s infinite" }} />
        </div>
        <div style={{ flex: 1, overflow: "hidden" }}>
          <div className="ticker-inner">
            {[
              ["SPEED", `${Math.round(speed)} KM/H`, "#00c8ff"],
              ["RPM", `${Math.round(rpm/100)*100}`, "#00ff88"],
              ["GEAR", gear, "#ffd93d"],
              ["TEMP", `${Math.round(temp)}°C`, "#ff6b6b"],
              ["RANGE", `${Math.round(range)} KM`, "#00ff88"],
              ["BATTERY", `${battery}%`, "#00c8ff"],
              ["TRACTION", "SPORT", "#ffd93d"],
              ["G-FORCE", `${Math.abs(gforce.y).toFixed(1)}G`, "#c77dff"],
              ["SYSTEM", "ALL OK", "#00ff88"],
              ["AI STATUS", "ACTIVE", "#00c8ff"],
              ["SPEED", `${Math.round(speed)} KM/H`, "#00c8ff"],
              ["RPM", `${Math.round(rpm/100)*100}`, "#00ff88"],
              ["GEAR", gear, "#ffd93d"],
              ["TEMP", `${Math.round(temp)}°C`, "#ff6b6b"],
              ["RANGE", `${Math.round(range)} KM`, "#00ff88"],
            ].map(([k, v, c], i) => (
              <div key={i} className="ticker-item mono">
                <span style={{ color: "rgba(255,255,255,0.3)" }}>{k}:</span>
                <span style={{ color: c, fontWeight: 700 }}>{v}</span>
                <span style={{ color: "rgba(255,255,255,0.15)", margin: "0 8px" }}>|</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* BOOT SCREEN */}
      <div className={`boot-screen${booted ? " out" : ""}`} style={{ pointerEvents: booted ? "none" : "all" }}>
        <div style={{ textAlign: "center" }}>
          <div className="hud-font" style={{
            fontSize: 52, fontWeight: 900, letterSpacing: 12,
            background: "linear-gradient(90deg,#00ff88,#00c8ff,#00ff88)",
            backgroundSize: "200%",
            WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
            backgroundClip: "text",
            marginBottom: 32,
          }}>AUTONEXUS</div>
          <div style={{
            width: 60, height: 60, border: "2px solid transparent",
            borderTop: "2px solid #00ff88", borderRight: "2px solid #00c8ff",
            borderBottom: "2px solid #00ff88", borderLeft: "2px solid #00c8ff",
            borderRadius: "50%", margin: "0 auto 32px",
            animation: "radarSpin 1s linear infinite",
          }} />
          <div className="mono" style={{ fontSize: 11, color: "rgba(0,255,136,0.6)", letterSpacing: 3, marginBottom: 12 }}>
            INITIALIZING NEURAL DRIVE SYSTEMS...
          </div>
          <div style={{ width: 360, maxWidth: "80vw", height: 5, background: "rgba(255,255,255,0.06)", borderRadius: 3, overflow: "hidden" }}>
            <div style={{
              height: "100%", background: "linear-gradient(90deg,#00ff88,#00c8ff)",
              width: `${loadProgress}%`, borderRadius: 3, transition: "width 0.2s ease",
              boxShadow: "0 0 12px rgba(0,255,136,0.8)",
            }} />
          </div>
          <div className="hud-font" style={{
            fontSize: 32, fontWeight: 900, color: "#00ff88",
            textShadow: "0 0 20px rgba(0,255,136,0.8)",
            marginTop: 14, letterSpacing: 4,
          }}>{Math.round(loadProgress)}%</div>
          <div className="mono" style={{ fontSize: 10, color: "rgba(255,255,255,0.25)", letterSpacing: 3, marginTop: 14 }}>
            v3.0.1 • NEURAL DRIVE AI • NEO-TOKYO READY
          </div>
        </div>
      </div>
    </div>
  );
}
